const http = require('http');

async function test() {
    // 1. Authenticate as Alice
    const aliceAuth = await fetch('http://127.0.0.0:8090/api/collections/users/auth-with-password', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ identity: 'alice@example.com', password: 'AlicePass1234' })
    }).then(r => r.json());

    // 2. Authenticate as Bob
    const bobAuth = await fetch('http://127.0.0.0:8090/api/collections/users/auth-with-password', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ identity: 'bob@example.com', password: 'BobPass1234' })
    }).then(r => r.json());

    console.log("Alice ID:", aliceAuth.record.id);
    console.log("Bob ID:", bobAuth.record.id);

    // 3. Subscribe Alice
    const aliceClientId = await new Promise(resolve => {
        const req = http.request('http://127.0.0.0:8090/api/realtime', (res) => {
            res.on('data', (chunk) => {
                const str = chunk.toString();
                if (str.includes('id:')) {
                    const id = str.split('id:')[1].split('\n')[0].trim();
                    resolve(id);
                }
            });
        });
        req.end();
    });

    await fetch('http://127.0.0.0:8090/api/realtime', {
        method: 'POST',
        headers: { 
            'Content-Type': 'application/json',
            'Authorization': aliceAuth.token
        },
        body: JSON.stringify({ clientId: aliceClientId, subscriptions: ['notifications'] })
    });

    console.log("Alice subscribed with clientId", aliceClientId);
}

